import { useState } from "react";
import { FaArrowLeft, FaEnvelope } from "react-icons/fa"; // Import icons
import { useNavigate } from "react-router-dom";
import "./forgotpassword.css"; // Import CSS
import axios from "axios"; // Import axios for API requests

const ForgotPassword = () => {
  const [email, setEmail] = useState("");
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!email) {
      setError("Email is required!");
      setSuccess(""); // Reset success message
      return;
    }

    if (!/\S+@\S+\.\S+/.test(email)) {
      setError("Enter a valid email address!");
      setSuccess("");
      return;
    }

    try {
      const response = await axios.post("http://localhost:5000/api/auth/forgot-password", { email });
      setSuccess(response.data.message);
      setError("");
    } catch (error) {
      setError(error.response?.data?.message || "Request failed❌");
      setSuccess("");
    }
  };

  return (
    <div className="forgot-password-container">
      {/* Back to Login Icon */}
      <div className="back-to-login" onClick={() => navigate("/")}>
        <FaArrowLeft />
      </div>

      <img src="/assets/ODCSE Logo.png" alt="Logo" className="logo" />

      <form onSubmit={handleSubmit} className="forgot-password-form">
        <div className="input-group">
          <FaEnvelope className="icon" />
          <input
            type="email"
            placeholder="College Mail ID"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
          />
        </div>

        {/* Instruction Text */}
        <p className="instruction-text">Enter a valid email address</p>

        <button type="submit" className="reset-button">Reset Password</button>

        {/* Error/Success Messages */}
        <div className="message-container">
          {error && <p className="error-message">{error}</p>}
          {success && <p className="success-message">{success}</p>}
        </div>
      </form>
    </div>
  );
};

export default ForgotPassword;
